// main.go

package main

import (
	"fmt"
	"log"
)

func main() {
	fmt.Println("Starting {{service_name}} service...")
	// Add initialization logic here
	log.Fatal(nil)
}
# Dockerfile

FROM golang:1.21 AS builder
WORKDIR /app
COPY go.mod .
COPY go.sum .
RUN go mod download
COPY . .
RUN CGO_ENABLED=0 GOOS=linux go build -a -installsuffix cgo -o {{service_name}} .

FROM alpine:latest
WORKDIR /root/
COPY --from=builder /app/{{service_name}} .
CMD ["./{{service_name}}"]
# docker-compose.yml

version: '3.8'
services:
  {{service_name}}:
    build: .
    ports:
      - "8080:8080"
    environment:
      DATABASE_URL: sqlite:///./data/database.db
      MESSAGING_BROKER: nats://nats:4222
    depends_on:
      - nats

  nats:
    image: nats:latest
    ports:
      - "4222:4222"
